import React, { useEffect, useState } from "react";

function App() {
  const [questions, setQuestions] = useState([]);
  const [current, setCurrent] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const controller = new AbortController();

    fetch("http://127.0.0.1:5000/api/games", {
      method: "GET",
      signal: controller.signal,
    })
      .then((res) => {
        if (!res.ok) {
          throw new Error(`HTTP error: ${res.status}`);
        }
        return res.json();
      })
      .then((data) => {
        console.log("Questions received:", data);
        setQuestions(data);
        setLoading(false);
      })
      .catch((err) => {
        console.error("Fetch error:", err);
        setError(err.message);
        setLoading(false);
      });

    return () => controller.abort();
  }, []);

  if (loading) {
    return <h2 style={{ textAlign: "center", marginTop: "50px" }}>Loading questions...</h2>;
  }

  if (error) {
    return (
      <div style={{ textAlign: "center", marginTop: "50px" }}>
        <h2>Error loading questions</h2>
        <p>{error}</p>
      </div>
    );
  }

  if (questions.length === 0) {
    return <h2 style={{ textAlign: "center", marginTop: "50px" }}>No questions found</h2>;
  }

  const question = questions[current];

  return (
    <div style={{ textAlign: "center", marginTop: "50px" }}>
      <h1>Quiz Game</h1>
      <h2>{question.question}</h2>

      {question.options.map((opt, index) => (
        <button
          key={index}
          style={{
            display: "block",
            margin: "10px auto",
            padding: "10px 20px",
            cursor: "pointer",
          }}
        >
          {opt}
        </button>
      ))}

      <button
        onClick={() => setCurrent((prev) => (prev + 1) % questions.length)}
        style={{ marginTop: "20px", padding: "10px 20px" }}
      >
        Next Question
      </button>
    </div>
  );
}

export default App;
